const MUOI_HAI_CUNG = {"Mệnh":{"y_nghia":["Cung Thái Cực — trung tâm mệnh bàn, mấu chốt thành bại cuộc đời","Cái ta VÔ HÌNH: tâm tư, suy nghĩ, tình cảm, ý chí, tinh thần","Trạng thái não bộ, hệ thần kinh, mong muốn nội tâm","Thế giới có sự tồn tại của ta mới có ý nghĩa — gốc rễ toàn bộ mệnh bàn"],"the_dung":["Tật của Giao Hữu → nhân duyên, cách tiếp xúc mọi người","Phúc Đức của Phu Thê → tinh thần suy nghĩ của vợ/chồng","Đứng đầu tam phương Mệnh–Tài–Sự → chi phối toàn bộ kiếm tiền sự nghiệp"],"luu_y":"Phi hóa từ Mệnh đi đến đâu = ta đang chú tâm muốn đầu tư vào đó","doi_cung":"Thiên Di","luc_loai":"noi"},"Huynh Đệ":{"y_nghia":["Tình duyên anh chị em, bạn bè cùng vai vế","Kho vị — Điền của Tài: kho cất giữ tiền bạc, tiết kiệm","Thành tựu sự nghiệp — Tật của Sự Nghiệp: quy mô thực tế","Chỉ về Mẹ (người sinh ra ta) và chuyện giường chiếu"],"the_dung":["Điền của Tài Bạch → kho tiềm lực kinh tế, tài sản tích lũy","Tật của Sự Nghiệp → quy mô thành tựu sự nghiệp","Sự của Tật Ách → thể chất sức khỏe tổng thể"],"luu_y":"Huynh Đệ có cát hóa = kho đầy. Hung hóa = khó giữ tiền kho rỗng","doi_cung":"Giao Hữu","luc_loai":"ngoai"},"Phu Thê":{"y_nghia":["Chủ tình duyên khác giới, người phối ngẫu (vợ/chồng)","Trạng thái hôn nhân, hạnh phúc đôi lứa, đời sống tình cảm","Đối tác chiến lược quan trọng nhất cuộc đời"],"the_dung":["Tài của Phúc Đức → tiền tài phúc phận","Tật của Điền Trạch → vận thế gia đình","Sự của Thiên Di → sự nghiệp của người bạn đời"],"luu_y":"Đối cung Sự Nghiệp: hôn nhân và sự nghiệp luôn ảnh hưởng lẫn nhau","doi_cung":"Sự Nghiệp","luc_loai":"ngoai"},"Tử Nữ":{"y_nghia":["Con cái, bề dưới, cấp dưới, học sinh, thú cưng","Chức năng tình dục, đời sống chăn gối, khả năng sinh sản","Dự án, sáng tạo do mình tạo ra và nuôi dưỡng"],"the_dung":["Sự của Giao Hữu → hợp tác quy mô nhỏ cá nhân","Tật của Phúc Đức → chất lượng cuộc sống lúc về già","Di của Điền Trạch → bên ngoài nhà ngoài sân xuất ngoại"],"luu_y":"Tình cảm ngoài hôn nhân khi có sao đào hoa hóa Lộc/Kỵ","doi_cung":"Điền Trạch","luc_loai":"ngoai"},"Tài Bạch":{"y_nghia":["Duyên tiền bạc, phương thức kiếm/tiêu tiền, ngành nghề","Thái độ nhìn nhận tiền bạc, ham muốn, giá trị quan vật chất","Cách tiếp thu kiến thức lúc đi học, phong cách học tập"],"the_dung":["Phu của Phu Thê → quan hệ đối đãi vợ chồng cơm áo gạo tiền","Điền của Giao Hữu → phòng khách","Di của Phúc Đức → biểu hiện tính khí sở thích bên ngoài"],"luu_y":"Đối cung Phúc Đức: tiền bạc ↔ tinh thần","doi_cung":"Phúc Đức","luc_loai":"noi"},"Tật Ách":{"y_nghia":["Thân thể hữu hình — Tật là bệnh tật, Ách là tai ách","Biểu hiện tính cách: thói quen, ngôn ngữ cơ thể","Phản ứng cảm xúc tự nhiên nhất — bản năng thật sự"],"the_dung":["Phúc của Giao Hữu → cách bạn bè nghĩ về ta","Sự của Điền Trạch → vận thế gia đình","Điền của Sự Nghiệp → môi trường nơi làm việc"],"luu_y":"Tật Ách có D: kén chọn bạn bè. Có A: ăn gì cũng được bạn ai cũng được","doi_cung":"Phụ Mẫu","luc_loai":"noi"},"Thiên Di":{"y_nghia":["Đi lại, dịch chuyển, duyên xuất ngoại, hình tượng xã hội","Cái ta HỮU HÌNH — đánh giá của xã hội đối với ta","Kỹ năng ứng biến, năng lực xã giao, trí tuệ bộc lộ ra ngoài"],"the_dung":["Đối cung Mệnh: Mệnh = ta vô hình ↔ Thiên Di = ta hữu hình","Tài Bạch của Phu Thê → tài chính năng lực kiếm tiền của vợ/chồng","Sự của Phu Thê → hình ảnh cá nhân vợ/chồng khi ra ngoài"],"luu_y":"Thiên Di là mặt ngoài của Mệnh — người ta nhìn thấy ta như thế nào","doi_cung":"Mệnh","luc_loai":"ngoai"},"Giao Hữu":{"y_nghia":["Quan hệ giao tiếp: đồng nghiệp, bạn học, người cùng vai vế","Tất cả mối quan hệ tiếp xúc — không nhất định phải quen biết","Mạng lưới xã hội rộng, cộng đồng, đám đông","Vi khuẩn, virus, bệnh từ bên ngoài môi trường"],"the_dung":["Tật của Phu Thê → chi tiêu hôn nhân mức độ hạnh phúc","Điền của Phúc Đức → nơi thờ thần linh điện Phật","Phúc của Điền Trạch → phần mộ tổ tiên"],"luu_y":"Vi khuẩn virus cũng là 'chúng sinh' — Nô Bộc hung hóa xung Tật = bệnh từ môi trường","doi_cung":"Huynh Đệ","luc_loai":"ngoai"},"Sự Nghiệp":{"y_nghia":["Trạng thái làm việc, ngành nghề, công việc bản thân","Công danh, quyền hành, chức vụ, địa vị xã hội","Số 9 = Cực Dương → còn gọi là cung Khí Số Vận Khí"],"the_dung":["Di của Phu Thê → hình ảnh cá nhân vợ/chồng khi ra ngoài","Tử Nữ của Tật Ách → sức khỏe sinh ra sự nghiệp","Điền của Phụ Mẫu → phòng học bàn học nơi học tập"],"luu_y":"Đối cung Phu Thê: sự nghiệp ↔ hôn nhân luôn liên hệ mật thiết","doi_cung":"Phu Thê","luc_loai":"noi"},"Điền Trạch":{"y_nghia":["Gia tộc, gia đình, gia phong, người nhà, đất đai nhà cửa","Tổng hợp của cải, gia tài — bất động sản là chủ","Đời sống vật chất, hoàn cảnh sống của gia đình"],"the_dung":["Tật của Tài Bạch → tài sản tích lũy nền tảng kinh tế","Chủ tam phương Điền → thành quả sau cùng cuộc đời"],"luu_y":"Tổ đức tốt xấu ảnh hưởng hưng thịnh gia đạo ít nhất 6 đời","doi_cung":"Tử Nữ","luc_loai":"noi"},"Phúc Đức":{"y_nghia":["Linh tính, thiên bẩm, thiên phú của ta","Tiên thiên: hưởng thụ, sở thích, thú vui cá nhân","Hậu thiên: làm từ thiện, tích đức, tu thân"],"the_dung":["Di của Tài Bạch → biểu tượng bên ngoài về ham muốn vật chất","Chủ tam phương Phúc → phúc phần đời người thăng trầm tuổi già"],"luu_y":"Đối cung Tài Bạch: tinh thần ↔ vật chất","doi_cung":"Tài Bạch","luc_loai":"noi"},"Phụ Mẫu":{"y_nghia":["Ba mẹ nói chung, nhưng chủ yếu mô tả người ba (cha)","Thầy giáo, bậc trên, cấp trên, sếp, cơ quan nhà nước","Học tập, đọc sách, học lực, bằng cấp","Cung văn thư, giấy tờ, hợp đồng. Quang Minh Hàm Dưỡng"],"the_dung":["Điền của Phu Thê → gia đình thông gia cưới hỏi","Tật của Thiên Di → quy phạm đạo đức hành xử ngoài xã hội","Tài của Giao Hữu → vay mượn tiền bạc ngân hàng"],"luu_y":"Phụ Mẫu chủ yếu mô tả người ba. Muốn xem về mẹ → xem Huynh Đệ","doi_cung":"Tật Ách","luc_loai":"ngoai"}};
const MUOI_HAI_CUNG_MO_RONG = {"Mệnh":{"nhan":{"co_ban":["Bản thân (Cái tôi vô hình - Tâm chi Ngã)."],"mo_rong":["Ông nội (cha của cha - Phúc), Cụ (cha của ông - Điền).","Bà ngoại, bác trai.","Đây là cung vị trực tiếp đại diện cho chính bản thân đương số: con người bẩm sinh, bản ngã sâu sắc nhất.","Phản ánh cá tính, phẩm chất, ưu điểm và nhược điểm cốt lõi của đương số.","Cho thấy tài hoa, năng lực và tiềm năng bẩm sinh của đương số trong cuộc sống.","Là nơi thể hiện thế giới nội tâm chân thực, những suy nghĩ, tư tưởng, triết lý sống sâu kín nhất.","Cung Mệnh còn có thể cho thấy ngoại hình và vóc dáng chung của đương số."]},"su":{"co_ban":["Suy nghĩ, phản ứng cảm xúc, hỉ nộ ái ố."],"mo_rong":["Vận thế kiếm tiền (đứng đầu tam phương Mệnh-Tài-Sự).","Biểu thị nhân duyên tiên thiên với sự nghiệp có hay không, tức là cho thấy đương số có duyên với con đường công danh, sự nghiệp hay không, và mức độ thành tựu có thể đạt được.","Chỉ ra định hướng và mục tiêu chung của cuộc đời đương số.","Đây là nơi thể hiện sức sống, ý chí và khả năng đương số định hình cuộc đời mình.","Cho thấy đương số có dễ gặp may mắn hay khó khăn ngay từ khởi đầu cuộc đời.","Khả năng đương số thích nghi với môi trường và đối mặt với thử thách."]},"vat":{"co_ban":["Tình cốt nhục, tay chân.","Duyên phận anh em."],"mo_rong":["Phòng của con cái (Điền trạch của Tử nữ).","Liên quan đến những bất trắc, những sự kiện đột ngột có thể xảy ra, vì Mệnh là 'Thể', là nơi hứng chịu tác động từ các cung khác.","Ảnh hưởng đến tình duyên, vì nó là 'Thể' của cung Phu Thê (Dụng), chất lượng hôn nhân tác động trực tiếp đến bản mệnh.","Có liên quan đến định số của tiền tài, vì nó là 'Thể' của cung Tài Bạch (Dụng), cho thấy khả năng giữ tiền và sự ảnh hưởng của tài chính lên cuộc sống.","Là cung vị liên quan đến sự độc lập và khả năng tự chủ của đương số.","Là cầu nối (Khí số) của Tật Ách (Sự của Tật).","Là cung vị thực lực kinh tế (Điền của Tài)."]}},"Huynh Đệ":{"nhan":{"co_ban":["Anh chị em ruột."],"mo_rong":["Mẹ (trong một số trường hợp mượn cung).","Bạn đời của anh em.","Đây là cung vị đại diện cho huynh đệ, tỷ muội (anh chị em ruột), cho thấy số lượng, tính cách và mối quan hệ giữa đương số với họ (hòa thuận hay xung khắc).","Trong nhiều trường phái, đây cũng là cung vị quan trọng để luận về mẫu thân (người mẹ), cho thấy mối quan hệ và sự ảnh hưởng của mẹ đối với đương số.","Phản ánh nhân duyên của đương số với những người ngang hàng, bạn bè thân thiết nhất, những người mà đương số có thể sẻ chia, tâm sự.","Cho thấy đương số có nhận được sự giúp đỡ, hỗ trợ từ anh chị em, mẹ và bạn thân hay ngược lại."]},"su":{"co_ban":["Sự hưng thịnh/suy vi của gia đạo."],"mo_rong":["Thành tựu sự nghiệp (Kết hợp giữa quy mô sự nghiệp và thực lực kinh tế).","Thể chất, sức khỏe.","Gửi tiền, tiết kiệm.","Là cung vị chủ về dịch mã, cho thấy các vấn đề liên quan đến sự di chuyển, đi lại, thay đổi công việc hoặc nơi ở trong cuộc sống.","Liên quan đến việc hợp tác làm ăn nhỏ lẻ, góp vốn bằng tiền mặt với người khác.","Thể hiện các hành vi vay mượn, nợ nần và khả năng tín dụng của đương số."]},"vat":{"co_ban":["Duyên phận khác giới.","Quan hệ hôn nhân."],"mo_rong":["Khố vị (Kho tiền, két sắt).","Phòng ngủ, giường ngủ (Điền trạch của Phu thê - nơi vợ chồng sinh hoạt).","Là 'kho tiền mặt' của đương số, biểu thị khả năng quản lý dòng tiền cá nhân và khả năng tiết kiệm.","Cho thấy sự ổn định hay bất ổn của dòng tiền vào/ra hàng ngày.","Có liên quan đến tài sản bất động sản theo một số cách luận cao cấp, vì nó là cung Điền Trạch của cung Tài Bạch (tài sản hình thành từ tiền bạc). Cung Phu Thê:.","Là cung Tài của Phúc (Tiền tài phúc phần).","Là cung Tật của Điền (Vận thế gia đình)."]}},"Phu Thê":{"nhan":{"co_ban":["Vợ hoặc chồng (Người phối ngẫu)."],"mo_rong":["Người khác giới bên ngoài (khi xét vận đào hoa).","Đây là cung vị trực tiếp đại diện cho phối ngẫu (người bạn đời) của đương số: tính cách, ngoại hình, hoàn cảnh gia đình, và số phận cơ bản của họ.","Phản ánh duyên khác giới của đương số nói chung: thuận lợi, được người khác giới giúp đỡ hay lận đận, gặp nhiều trắc trở.","Các sao tại đây mô tả mong muốn và kỳ vọng của đương số về một người bạn đời lý tưởng."]},"su":{"co_ban":["Tình cảm hôn nhân."],"mo_rong":["Vận xuất ngoại (Sự nghiệp của Thiên Di).","Phúc phần ngày nhỏ (nằm trong tam phương Phúc).","Là tấm gương phản chiếu cách cục sự nghiệp tiên thiên, cho thấy tiềm năng, quy mô và môi trường làm việc của đương số.","Cho thấy thời điểm đương số có khả năng kết hôn và những sự kiện quan trọng trong đời sống tình cảm như đính hôn, ly thân, ly hôn.","Chỉ ra những khó khăn, thách thức hoặc may mắn mà đương số có thể gặp phải trong tình yêu và hôn nhân."]},"vat":{"co_ban":["Chức năng sinh sản, đời sống tình dục.","Sự tiếp nối dòng dõi."],"mo_rong":["Nhà bếp (Điền trạch của Tật Ách - nơi tạo ra sức khỏe cho cơ thể).","Biểu thị bản chất của quan hệ đối đãi trong hôn nhân: cách vợ chồng tương tác, giao tiếp và đối xử với nhau hàng ngày.","Phản ánh mối quan hệ của đương số với gia đình nhà vợ/chồng.","Cung Phu Thê có thể ảnh hưởng đến sự nghiệp và tài chính của đương số thông qua người bạn đời hoặc các mối quan hệ tình cảm.","Đây là cung vị liên quan đến khả năng đương số xây dựng một gia đình hạnh phúc và ổn định.","Các bài học về sự sẻ chia, thấu hiểu và cam kết trong tình yêu được phản ánh ở đây. Cung Tử Nữ:.","Cung hưởng thụ của cơ thể (Phúc đức của Tật Ách).","Cung đào hoa (sau hôn nhân)."]}},"Tử Nữ":{"nhan":{"co_ban":["Con cái.","Cấp dưới, học sinh, vãn bối.","Thú cưng."],"mo_rong":["Thông gia (quan hệ xã giao do hôn nhân mang lại).","Chị em dâu (Phu thê của Huynh đệ).","Đối tác hợp tác.","Đây là cung vị trực tiếp đại diện cho con cái của đương số: số lượng, tính cách, sức khỏe, và số phận cơ bản của chúng.","Phản ánh mối quan hệ giữa đương số và con cái: hòa hợp hay xung đột, gần gũi hay xa cách.","Cũng là cung vị của học sinh, cấp dưới trực tiếp quản lý và mối quan hệ giữa đương số với họ.","Là cung vị quan trọng để xem xét về đào hoa và duyên khác giới bên ngoài các mối quan hệ chính thức.","Có thể báo hiệu những bất trắc, rắc rối liên quan đến con cái hoặc các mối quan hệ tình cảm."]},"su":{"co_ban":["Đời sống chăn gối.","Hợp tác quy mô nhỏ (Sự nghiệp của Giao hữu)."],"mo_rong":["Chất lượng cuộc sống khi về già (Tật Ách của Phúc Đức).","Dịch động, xuất ngoại (Thiên Di của Điền Trạch).","Chủ về dịch mã, các hoạt động di chuyển, thay đổi nơi ở, hoặc thường xuyên phải đi công tác xa nhà.","Là nơi thể hiện các hoạt động hợp tác hùn vốn, đầu tư kinh doanh cùng người khác.","Cho thấy kết quả của các hoạt động đầu tư và hợp tác của đương số (thành công hay thất bại).","Tượng trưng cho cửa hàng, nơi kinh doanh, hoặc địa điểm hoạt động, giải trí bên ngoài."]},"vat":{"co_ban":["Duyên tiền bạc.","Giá trị quan về tiền tệ."],"mo_rong":["Bên ngoài nhà, sân trước (Thiên Di của Điền Trạch).","Là cung vị chủ quản về các dự án hợp tác hùn vốn và kết quả của chúng.","Liên quan đến sức khỏe sinh sản và các vấn đề liên quan đến cơ quan sinh dục.","Là cung vị thể hiện sự hưởng thụ, giải trí và các mối quan hệ xã giao vui vẻ.","Là cung vị thể hiện sự hưởng thụ thể xác, nhục dục.","Cung vị đối đãi của vợ chồng (Phu thê của Phu thê)."]}},"Tài Bạch":{"nhan":{"co_ban":["(Ít dùng để chỉ người cụ thể, chủ yếu là vật/sự)."],"mo_rong":["Là cung vị quan trọng để xem xét về đối tượng tình cảm hoặc hôn nhân (phối ngẫu), đặc biệt là cách đương số đối đãi và tương tác với họ trong mối quan hệ."]},"su":{"co_ban":["Phương thức kiếm tiền và tiêu tiền.","Chi phí sinh hoạt (cơm áo gạo tiền)."],"mo_rong":["Biểu hiện tính khí, sở thích (Thiên Di của Phúc Đức).","Cho thấy thiên hướng kiếm tiền của đương số, giúp phân ra làm người đầu tư hay người đi làm (kinh doanh tự thân hay làm công ăn lương).","Phản ánh các nguồn thu nhập chính của đương số (lương, kinh doanh, đầu tư...).","Là nơi thể hiện thái độ của đương số đối với tiền bạc, cách chi tiêu và mức độ quan tâm đến tài chính.","Liên quan đến khả năng đầu tư và kinh doanh của đương số."]},"vat":{"co_ban":["Tiền mặt, tài sản lưu động.","Thân thể (Cái tôi hữu hình - Thân chi Ngã).","Nơi chứa đựng tâm hồn (nhất lục cộng tông với Mệnh)."],"mo_rong":["Phòng khách (Điền trạch của Giao hữu - nơi tiếp khách).","Biểu thị cơ duyên tài vận tiên thiên, tức khả năng kiếm tiền bẩm sinh và mức độ may mắn về tiền bạc của đương số.","Đây là cung vị trực tiếp đại diện cho khả năng quản lý tài chính và tích lũy tài sản của đương số.","Phản ánh tình hình tài chính hiện tại và tiềm năng tài lộc trong tương lai.","Cho thấy đương số có dễ gặp thua lỗ, nợ nần hay không, và khả năng quản lý các nghĩa vụ tài chính.","Là cung vị liên quan đến sự ổn định hoặc biến động trong tình hình tài chính của đương số.","Cung vị hưởng thụ (Phúc của Nô - tiếp xúc thân xác)."]}},"Tật Ách":{"nhan":{"co_ban":["Cơ thể của chính mình."],"mo_rong":["Phản ánh tư duy và tính tình sâu kín, những phản ứng bản năng, tiềm thức của đương số mà đôi khi chính đương số cũng không nhận ra.","Thể hiện mức độ lao lực của đương số, cả về thể chất lẫn tinh thần trong cuộc sống."]},"su":{"co_ban":["Bệnh tật, tai ách.","Biểu hiện tính cách qua ngôn ngữ cơ thể."],"mo_rong":["Mức độ hạnh phúc tình cảm (Sự ngọt ngào trong hôn nhân).","Vận thế gia đình (Sự nghiệp của Điền Trạch).","Cho thấy cách thức làm việc, liệu thân thể có phải lao lực để kiếm tiền hay không, công việc nặng nhọc hay nhẹ nhàng.","Liên quan mật thiết đến nghiệp lực từ kiếp trước ảnh hưởng đến thân thể và những bài học đương số phải trải qua."]},"vat":{"co_ban":["Thân thể vật lý.","Sự dịch chuyển, đi lại.","Biểu tượng bên ngoài (Mặt mũi, sĩ diện)."],"mo_rong":["Nơi làm việc, văn phòng, nhà xưởng (Điền trạch của Sự nghiệp - môi trường làm việc).","Đây là cung vị trực tiếp đại diện cho tình trạng khỏe mạnh, sức khỏe thể chất và tinh thần của đương số.","Phản ánh khả năng mắc bệnh, loại bệnh dễ gặp và mức độ nghiêm trọng.","Cho thấy khả năng gặp nạn ách, tai nạn, chấn thương, hoặc những chuyện bất ngờ liên quan đến thân thể.","Chỉ ra sự dẻo dai, sức bền bỉ của cơ thể và khả năng phục hồi sau bệnh tật.","Là cung vị liên quan đến sự sống còn và tuổi thọ (khi kết hợp với các cung vị khác).","Cung vị quả báo (Sự nghiệp của Phúc Đức).","Năng lực xã giao."]}},"Thiên Di":{"nhan":{"co_ban":["Người lạ, người trong xã hội.","Quý nhân bên ngoài."],"mo_rong":["Là tấm gương phản chiếu cá tính của đương số khi ra ngoài xã hội, cách người khác nhìn nhận và đánh giá về đương số.","Liên quan mật thiết đến phu thê (người bạn đời), đặc biệt là năng lực, hành vi và cách kiếm tiền của họ.","Là một trong những cung vị quan trọng để xem xét vận về già, cho thấy cuộc sống khi về hưu có an nhàn, được kính trọng hay không."]},"su":{"co_ban":["Đi xa, xuất ngoại.","Đánh giá của xã hội đối với mình.","Kỹ năng ứng biến xã hội."],"mo_rong":["Phúc vận, triển vọng tương lai (nằm trong tam phương Phúc).","Già vận (vận mệnh lúc già).","Đây là cung vị chủ về dịch mã, cho thấy tất cả các hoạt động di chuyển, đi lại, từ việc nhỏ như ra khỏi nhà đến việc lớn như xuất ngoại, nhập cư.","Phản ánh khả năng gặp may mắn hoặc rủi ro khi ra ngoài, đi xa, du lịch, hay công tác.","Liên quan đến danh tiếng và uy tín của đương số trong xã hội."]},"vat":{"co_ban":["Hình tượng bên ngoài.","Các mối quan hệ xã hội (chúng sinh).","Tình nghĩa."],"mo_rong":["Biểu thị tất cả nhân duyên xuất ngoại, tức là các mối quan hệ xã hội, quý nhân hay tiểu nhân khi đương số hoạt động ở môi trường bên ngoài.","Đây là cung vị trực tiếp đại diện cho môi trường bên ngoài nơi đương số hoạt động, ngoài ngôi nhà và quê hương.","Cho thấy các cơ hội và thách thức đến với đương số từ xã hội.","Cung Tật của Phu (Tình trạng sức khỏe/hạnh phúc của hôn nhân)."]}},"Giao Hữu":{"nhan":{"co_ban":["Bạn bè, đồng nghiệp.","Người cùng thế hệ, cùng trang lứa.","Quần chúng (không nhất thiết phải quen biết)."],"mo_rong":["Thần linh, Tổ tiên (liên quan đến thờ cúng).","Đây là cung vị trực tiếp đại diện cho bạn bè, cấp dưới, đồng nghiệp, vãn bối (thế hệ sau hoặc người nhỏ tuổi hơn).","Phản ánh chất lượng và số lượng của các mối quan hệ xã hội rộng lớn của đương số.","Là một trong những cung vị quan trọng để xem xét về đào hoa và duyên khác giới trong các mối quan hệ xã hội rộng, đôi khi ám chỉ người thứ ba."]},"su":{"co_ban":["Sự cạnh tranh, thi cử (dùng trong thi đấu, bầu cử)."],"mo_rong":["Tích đức hành thiện (Điền trạch của Phúc Đức - kho chứa phúc).","Liên quan trực tiếp đến các hoạt động hợp tác hùn vốn và chất lượng của quan hệ nhân tế (đối nhân xử thế).","Cho thấy sự giúp đỡ hoặc rắc rối, thị phi, thậm chí là sự phản bội mà đương số có thể gặp phải từ những người trong vòng xã giao.","Phản ánh khả năng đương số làm việc nhóm hiệu quả và quản lý nhân viên."]},"vat":{"co_ban":["Cách thức làm việc.","Vận khí (Khí số vị)."],"mo_rong":["Bàn thờ, nơi thờ cúng, miếu đường (Điền trạch của Phúc Đức).","Mộ tổ tiên (Phúc đức của Điền Trạch - Phúc phần của dòng họ).","Phản ánh các vấn đề liên quan đến vay mượn, nợ nần với người ngoài.","Nó cho thấy uy tín tín dụng của đương số.","Là cung vị ảnh hưởng gián tiếp đến tài chính và sự nghiệp của đương số thông qua các mối quan hệ đối tác và xã hội.","Cung Di của Phu (Hoạt động bên ngoài của người phối ngẫu)."]}},"Sự Nghiệp":{"nhan":{"co_ban":["(Ít dùng chỉ người, chủ yếu là công việc)."],"mo_rong":["Người tình (Đào hoa ngoài luồng - Di của Phu).","Là một cung vị quan trọng để xem xét về duyên khác giới và nhân duyên nam nữ, đặc biệt là các mối quan hệ nảy sinh trong môi trường công việc, xã hội."]},"su":{"co_ban":["Công việc, nghề nghiệp.","Thái độ làm việc."],"mo_rong":["Ngoại tình (nếu có sao đào hoa hóa Lộc/Kị).","Vận khí, sự may mắn (Số 9 - Cực dương).","Đây là cung vị trực tiếp đại diện cho công tác, sự nghiệp, nghề nghiệp, và con đường công danh của đương số.","Phản ánh loại hình công việc hoặc ngành nghề đương số có khả năng theo đuổi và phù hợp.","Liên quan đến môi trường học tập, trường học và con đường học vấn để phục vụ sự nghiệp.","Cho thấy khả năng đương số thăng tiến, đạt được vị trí cao và có ảnh hưởng trong công việc.","Phản ánh mối quan hệ của đương số với đồng nghiệp, cấp trên, cấp dưới."]},"vat":{"co_ban":["Sự thu tàng (cất giữ).","Gia phong, nề nếp."],"mo_rong":["Bàn học, phòng học (Điền trạch của Phụ mẫu - Nơi học tập).","Mộ tổ tiên (Phúc đức của Phúc đức - nguồn gốc của phúc).","Biểu thị vận thế tiên thiên mạnh hay kém, tức là tiềm năng và mức độ may mắn bẩm sinh của đương số trong cuộc sống.","Chỉ ra danh tiếng và uy tín của đương số trong lĩnh vực chuyên môn.","Phản ánh tính chất của công việc (ổn định hay biến động, áp lực hay thoải mái).","Là nơi thể hiện năng lực làm việc và khả năng đạt được thành tựu của đương số.","Cung Tật của Tài (Gốc rễ của tiền tài).","Cung thành quả cuối cùng của đời người."]}},"Điền Trạch":{"nhan":{"co_ban":["Người nhà, gia tộc."],"mo_rong":["Cụ (cha của ông nội).","Vợ (xét về vai trò tay hòm chìa khóa, vượng gia).","Đại diện cho gia tộc, thân thích, và gia đình nhỏ của đương số, bao gồm những người sống chung dưới một mái nhà.","Phản ánh nhân duyên gia vận, tức là phúc khí, sự hòa thuận hay mâu thuẫn trong nội bộ gia đình."]},"su":{"co_ban":["Đời sống vật chất gia đình.","Sự hưng vong của gia đạo."],"mo_rong":["Sự tích lũy.","Liên quan đến các sự kiện như dọn nhà, chuyển đổi nơi ở, sự ổn định hay biến động của môi trường sống.","Có thể báo hiệu những sự kiện bất ngờ xảy ra trong gia đình hoặc liên quan đến tài sản, nhà cửa.","Là cung vị quan trọng để xem về nơi kinh doanh như cửa hàng, công xưởng, văn phòng làm việc."]},"vat":{"co_ban":["Nhà cửa, đất đai, bất động sản.","Động sản, gia tài.","Linh tính (phần Trí/Linh).","Nhân quả, nghiệp lực."],"mo_rong":["Phần mộ của bản thân (Nơi quy túc sau cùng).","Cửa hàng (nếu kinh doanh tại gia).","Đây là cung vị trực tiếp đại diện cho nhà cửa, đất đai, và tài sản cố định mà đương số sở hữu.","Biểu thị sản nghiệp (tài sản đương số tự gầy dựng) và tổ nghiệp (tài sản được thừa kế từ cha mẹ, tổ tiên).","Cho thấy cách cục bất động sản tiên thiên, tức là số phận, duyên nợ của đương số với nhà đất mạnh hay kém.","Phản ánh khả năng đương số tích lũy, quản lý và giữ gìn tài sản.","Là nơi thể hiện cảm giác an toàn, sự thuộc về của đương số trong tổ ấm.","Cung Di của Tài (Biểu hiện của cách tiêu tiền)."]}},"Phúc Đức":{"nhan":{"co_ban":["Ông nội (cha của cha - Phụ của Phụ)."],"mo_rong":["Là cung vị xem về ông bà và sự ảnh hưởng của họ đến cuộc sống của đương số.","Đây là cung vị trực tiếp đại diện cho phúc báo, là nhân quả vị, nơi thể hiện nghiệp quả từ tổ tiên và tiền kiếp.","Phản ánh không khí của tổ ấm, sự ấm cúng và phúc khí của dòng họ.","Liên quan đến đời sống tinh thần, tư tưởng, triết lý sống và quan niệm của đương số về cuộc đời."]},"su":{"co_ban":["Hưởng thụ, sở thích, thú vui.","Tuổi thọ (Thọ nguyên - Tật của Tật).","Tinh thần, tư tưởng chiều sâu."],"mo_rong":["Vận phúc (nhân quả tiền kiếp và tích đức hiện đời).","Biểu thị các sở thích, ham mê và cách đương số theo đuổi chúng.","Cho thấy khả năng hưởng thụ cuộc sống, tìm thấy niềm vui và sự an lạc của đương số.","Phản ánh sức khỏe tinh thần, mức độ lạc quan hay bi quan, khả năng đối diện với áp lực tâm lý."]},"vat":{"co_ban":["Mộ phần của bản thân (sau khi mất - Thân hậu quy túc).","Cung dưỡng dục, che chở.","Văn thư, bằng sắc."],"mo_rong":["Có sự liên hệ ngầm, đề cập đến việc kiếm tiền thông qua tư tưởng, phúc phận và sự may mắn.","Liên quan đến các hoạt động giải trí, tiêu khiển và cách đương số tìm kiếm niềm vui.","Là nơi thể hiện sự may mắn hoặc rủi ro mang tính 'trời cho', ít phụ thuộc vào nỗ lực cá nhân.","Cung Tật của Di (Thực chất của hình ảnh bên ngoài - Đạo đức)."]}},"Phụ Mẫu":{"nhan":{"co_ban":["Cha mẹ (chủ về Cha).","Thầy cô, cấp trên, sếp."],"mo_rong":["Chủ nợ/Người vay (Tài của Giao hữu).","Đây là cung vị trực tiếp đại diện cho cha mẹ, trưởng bối (người lớn tuổi), thủ trưởng (cấp trên), và các quý nhân có vai vế.","Phản ánh mối quan hệ của đương số với cha mẹ và bề trên (hòa hợp hay xung khắc, nhận được sự giúp đỡ hay phải chịu áp lực).","Cung này cũng cho thấy mối quan hệ với khách hàng, đặc biệt là những khách hàng lớn, quan trọng."]},"su":{"co_ban":["Học tập, bằng cấp (do nhà nước chứng nhận).","Danh tiếng, đạo đức xã hội (Cung Quang minh)."],"mo_rong":["Gia đình của vợ/chồng (Điền trạch của Phu thê).","Vay mượn, giao dịch ngân hàng.","Liên quan đến các cơ quan công quyền như nhà nước, các tổ chức tài chính như ngân hàng, và môi trường giáo dục như trường học.","Là nơi xem xét về công danh, địa vị và các ngành nghề đặc thù như nghề phục vụ, nghề môi giới, nghề bảo hiểm.","Thể hiện khả năng đương số đối diện với các vấn đề pháp luật, quy tắc của xã hội."]},"vat":{"co_ban":["Cơ quan nhà nước.","Giấy tờ, văn thư, hợp đồng."],"mo_rong":["Ngân hàng, tổ chức tín dụng (Tài của Giao hữu).","Biểu thị các vấn đề liên quan đến văn thư, giấy tờ, hợp đồng, bằng cấp.","Là cung vị quan trọng để xem xét các cơ hội hợp tác chính thức, đòi hỏi sự tin tưởng và giấy tờ pháp lý.","Đại diện cho các đối tác ở thượng du (nguồn cung cấp, nhà sản xuất).","Phản ánh sức khỏe ở vùng đầu và mặt của đương số."]}}};
